const c="http://localhost:5000/api";async function t(s,n={}){const o={"Content-Type":"application/json",...n.headers||{}};try{const e=await window.Clerk?.session?.getToken();console.log(`📡 [API CLIENT] Path: ${s} | Has Clerk Token: ${e?"YES":"NO"}`),e&&(o.Authorization=`Bearer ${e}`)}catch(e){console.warn("Could not get Clerk session token:",e)}const a=await fetch(`${c}${s}`,{...n,headers:o}),r=await a.json().catch(()=>({}));if(!a.ok)throw new Error(r?.message||"Request failed");return r}async function i(){return t("/session/start",{method:"POST"})}async function h(s){return t("/session/end",{method:"POST",body:JSON.stringify({sessionId:s})})}async function u(s){return t("/focus/save",{method:"POST",body:JSON.stringify(s)})}async function f(s){return t(`/report/${s}`,{method:"GET"})}async function d(){return t("/session/stats",{method:"GET"})}async function l(){return t("/session/all",{method:"GET"})}export{i as a,l as b,f as c,h as e,d as f,u as s};
